texttool_globals_edit_text_error___confirm_spin_check_error_blocked_no_duration = TextObject(bs_BA="Unos PIN-a je privremeno blokiran.", cs_CZ="Zadání PINu je dočasně zablokováno.", da_DK="Pinkodeangivelse midlertidigt spærret.", de_DE="Die PIN-Eingabe ist vorübergehend gesperrt.", el_GR="Η καταχώριση PIN είναι φραγμένη προσωρινά.", en_GB="It is temporarily not possible to enter a PIN.", es_ES="El PIN no se puede introducir temporalmente.", fi_FI="PIN-koodin syöttäminen on tilapäisesti lukittu.", fr_FR="L'entrée du code PIN est bloquée temporairement.", hr_HR="Unos PIN-a privremeno je blokiran.", hu_HU="A PIN-kód megadása átmenetileg le van tiltva.", it_IT="L'immissione PIN è temporaneamente bloccata.", nl_NL="De pincode-invoer is voorlopig geblokkeerd.", no_NO="Innlegging av PIN-kode er midlertidig sperret.", pl_PL="Wprowadzanie kodu PIN jest tymczasowo zablokowane.", pt_PT="A introdução do PIN está temporariamente bloqueada.", ro_RO="Introducerea codului PIN este blocată temporar.", ru_RU="Ввод PIN-кода временно заблокирован.", sk_SK="Zadanie PIN kódu je dočasne zablokované.", sl_SI="Vnos PIN-kode je začasno blokiran.", sr_RS="Unos PIN-a je privremeno blokiran.", sv_SE="PIN-kodsinmatningen har spärrats temporärt.", tr_TR="PIN girişi geçici olarak kilitlenmiştir.", uk_UA="Введення ПІН-коду тимчасово заблоковано.")
texttool_globals_edit_text_error___confirm_spin_check_error_blocked_offline = TextObject(bs_BA="Za daljnju provjeru vašeg myAudi PIN-a neophodna je\nveza sa internetom. Uspostavite vezu sa internetom i\npokušajte ponovo.", cs_CZ="Pro další kontrolu svého PINu myAudi potřebujete\npřipojení k internetu. Vytvořte připojení k internetu a\npak to zkuste znovu.", da_DK="Internetforbindelse er nødvendigt for at kunne\nkontrollere din myAudi-pinkode yderligere. Opret\ninternetforbindelse, og forsøg derefter igen.", de_DE="Für eine weitere Prüfung deiner myAudi PIN wird\neine Internetverbindung benötigt.\nBitte stelle eine Internetver­bindung her und versuche\nes anschließend erneut.", el_GR="Για τον περαιτέρω έλεγχο του myAudi PIN σας\nαπαιτείται μια σύνδεση με το διαδίκτυο. Δημιουργήστε\nμια σύνδεση με το διαδίκτυο και στη συνέχεια\nπροσπαθήστε εκ νέου.", en_GB="An internet connection is required for a further check\nof your myAudi PIN. Please establish an internet\nconnection and then try again.", es_ES="Una comprobación más exhaustiva de su PIN myAudi\nrequiere conexión a Internet. Conéctese a Internet y\nvuelva a intentarlo.", fi_FI="myAudi-PIN-koodin tarkastamista varten tarvitaan\ninternetyhteys. Muodosta internetyhteys ja yritä sitten\nuudelleen.", fr_FR="Une connexion Internet est requise pour une\nvérification complémentaire de votre code PIN\nmyAudi. Veuillez établir une connexion Internet puis\nréessayez.", hr_HR="Za dodatnu provjeru vašeg myAudi PIN-a potrebna je\ninternetska veza. Uspostavite internetsku vezu i\npokušajte nakon toga ponovno.", hu_HU="A myAudi PIN-kódod további ellenőrzéséhez\ninternetkapcsolat szükséges. Kérjük, csatlakozz az\ninternethez, majd próbáld újra.", it_IT="Per un ulteriore controllo del PIN myAudi è necessario\nun collegamento a internet. Si prega di collegarsi a\ninternet e riprovare.", nl_NL="Voor verdere controle van je myAudi PIN is internet\nvereist. Maak verbinding met internet en probeer het\nopnieuw.", no_NO="En ny kontroll av myAudi-PIN krever\ninternettforbindelse. Opprett internettforbindelse og\nprøv igjen.", pl_PL="Do dalszej kontroli Twojego kodu PIN myAudi\nwymagane jest połączenie z Internetem. Nawiąż\npołączenie z Internetem i spróbuj ponownie.", pt_PT="Para uma verificação adicional do teu PIN myAudi é\nnecessária uma ligação à Internet. Por favor,\nestabelece uma ligação à Internet e depois volta a\ntentar.", ro_RO="Pentru verificarea suplimentară a codului PIN myAudi\neste necesară o conexiune la Internet. Realizaţi o\nconexiune la Internet, apoi reîncercaţi.", ru_RU="Для дальнейшей проверки PIN myAudi требуется\nсоединение с интернетом. Установите\nинтернет-соединение и повторите попытку.", sk_SK="Na ďalšiu kontrolu vášho PIN kódu myAudi je potrebné\ninternetové pripojenie. Prosím, vytvorte internetové\npripojenie a poskúste sa o to neskôr znova.", sl_SI="Za dodatno preverjanje vaše PIN-kode myAudi je\npotrebna internetna povezava. Vzpostavite internetno\npovezavo in nato poskusite znova.", sr_RS="Za daljnju proveru vašeg myAudi PIN-a potrebna je\ninternet veza. Uspostavite internet vezu i pokušajte\nponovo.", sv_SE="En internetanslutning krävs för en bättre kontroll av\ndin myAudi-PIN. Upprätta en internetanslutning och\nförsök sedan igen.", tr_TR="myAudi PIN'ini daha ayrıntılı kontrol etmek için bir\ninternet bağlantısı gereklidir. Lütfen bir internet\nbağlantısı oluştur ve ardından tekrar dene.", uk_UA="Для подальшої перевірки PIN myAudi потрібне\nз'єднання з Інтернетом. Встановіть з'єднання з\nІнтернетом і повторіть спробу.")
texttool_globals_edit_text_error___confirm_spin_check_error_generic = TextObject(bs_BA="Došlo je do tehničke greške. Provjera\novlaštenja je bila neuspješna.", cs_CZ="Vyskytla se technická chyba. Kontrola oprávnění je\nneúspěšná.", da_DK="Teknisk fejl opstået.\nBeføjelseskontrol mislykkedes.", de_DE="Es ist ein technischer Fehler aufgetreten.\nDie Berechtigungsprüfung ist fehlgeschlagen.", el_GR="Προέκυψε τεχνικό σφάλμα. Ο έλεγχος εξουσιοδότησης\nαπέτυχε.", en_GB="A technical error has occurred. The authorisation\ncheck failed.", es_ES="Se ha producido un error técnico.\nLa comprobación de permisos ha fallado.", fi_FI="Tekninen virhe. Oikeuksien tarkastus epäonnistui.", fr_FR="Une erreur technique s'est produite.\nÉchec du contrôle de l'autorisation.", hr_HR="Nastupila je tehnička greška. Provjera odobrenja nije\nuspjela.", hu_HU="Technikai hiba lépett fel. A jogosultság ellenőrzése\nsikertelen volt.", it_IT="Si è verificato un errore tecnico. Il controllo delle\nautorizzazioni è fallito.", nl_NL="Er is een technische fout opgetreden. De\nautorisatiecontrole is mislukt.", no_NO="Det har oppstått en teknisk feil.\nRettighetskontrollen mislyktes.", pl_PL="Wystąpił błąd techniczny. Kontrola uprawnień nie\npowiodła się.", pt_PT="Ocorreu uma falha técnica. A verificação da permissão\nfalhou.", ro_RO="A apărut o eroare tehnică. Verificarea drepturilor a\neşuat.", ru_RU="Произошла техническая ошибка. Проверка\nавторизации не удалась.", sk_SK="Vyskytla sa technická chyba.\nKontrola oprávnenia sa nepodarila.", sl_SI="Prišlo je do tehnične napake. Preverjanje pooblastila ni\nuspelo.", sr_RS="Došlo je do tehničke greške. Provera ovlašćenja je bila\nneuspešna.", sv_SE="Ett tekniskt fel har uppstått. Behörighetskontrollen\nmisslyckades.", tr_TR="Teknik bir sorun oluştu. Yetkilendirme denetimi\nbaşarısız oldu.", uk_UA="Сталася технічна помилка. Перевірка авторизації не\nвдалася.")
texttool_globals_edit_text_error___confirm_spin_check_error_no_connection = TextObject(bs_BA="Došlo je do greške u povezivanju. Pokušajte ponovo.", cs_CZ="Vyskytla se chyba spojení. Zkuste to prosím znovu.", da_DK="Forbindelsesfejl opstået.\nForsøg igen.", de_DE="Es ist ein Verbindungsfehler aufgetreten.\nBitte versuche es erneut.", el_GR="Προέκυψε σφάλμα σύνδεσης. Προσπαθήστε πάλι.", en_GB="A connection error has occurred. Please try again.", es_ES="Se ha producido un error de conexión.\nPor favor, inténtelo de nuevo.", fi_FI="Yhteysvirhe. Yritä myöhemmin uudelleen.", fr_FR="Une erreur de connexion s'est produite.\nVeuillez réessayer.", hr_HR="Nastupila je greška u vezi. Pokušajte ponovno.", hu_HU="Kapcsolódási hiba lépett fel. Kérünk, próbáld újra.", it_IT="Si è verificato un errore di collegamento. Si prega di\nriprovare.", nl_NL="Er is een verbindingsfout opgetreden. Probeer het\nopnieuw.", no_NO="Det har oppstått en forbindelsesfeil.\nPrøv på nytt.", pl_PL="Wystąpił błąd połączenia.\nProszę spróbować ponownie.", pt_PT="Ocorreu uma falha na ligação. Por favor, volta a\ntentar.", ro_RO="A apărut o eroare de conectare. Reîncercaţi.", ru_RU="Произошла ошибка подключения. Пожалуйста,\nпопробуйте еще раз.", sk_SK="Vyskytla sa chyba pripojenia.\nProsím, pokúste sa o to znovu.", sl_SI="Prišlo je do napake v povezavi. Poskusite znova.", sr_RS="Došlo je do greške u povezivanju. Pokušajte ponovo.", sv_SE="Ett anslutningsfel har uppstått. Försök igen.", tr_TR="Bir bağlantı hatası oluştu. Lütfen yeniden dene.", uk_UA="Сталася помилка підключення. Будь ласка,\nспробуйте ще раз.")
